def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                inner_sum = 0
                for n in range(1, k+1):
                    inner_sum += ((-1)**n) * (ratio ** (2 * n)) / (n + k)
                penalty += inner_sum / (k * 3)
            priorities[i] = (ratio ** 4) + penalty * 2
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                term = sign * (ratio ** (j+1)) / (j ** 2)
                score += term
            multiplier = 20 if ratio > 1.5 else 12
            priorities[i] = abs(score) * multiplier + (ratio - 1) * 5
            if ratio > 1.8:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1)**(m+1)) * (ratio ** m) / (m * 2)
                priorities[i] += extra * 3
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = (-1) ** (j+1)
                term = sign * (ratio ** j) / (j + 1)
                score += term
            multiplier = 25 if ratio < 0.25 else 18 if ratio < 0.5 else 8
            priorities[i] = abs(score) * multiplier
            if 0.75 < ratio <= 1:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** (2*m - 1)) / (m * 3)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                if capacity < item / 10:
                    priorities[i] = np.inf / 2
                else:
                    priorities[i] = np.inf
    for idx in range(len(priorities)):
        if np.isfinite(priorities[idx]):
            scale_factor = 1
            for power in range(1, 4):
                scale_factor *= (1 + ((bins[idx] / (item + 1)) ** (power)) / (power + 1))
            priorities[idx] *= scale_factor
            if priorities[idx] > 1000:
                priorities[idx] = 1000 + np.log1p(priorities[idx] - 1000)
    return priorities
